import{_ as a,c as i,o as e,aj as s,b8 as r,b9 as l,ba as d,bb as h,bc as p,bd as n,be as o,bf as c,bg as b}from"./chunks/framework.CoirRWyn.js";const f=JSON.parse('{"title":"2.6 用AI写作 [Writing with AI]","description":"","frontmatter":{},"headers":[],"relativePath":"module_2/2.6用AI写作[Writing with AI].md","filePath":"module_2/2.6用AI写作[Writing with AI].md"}'),g={name:"module_2/2.6用AI写作[Writing with AI].md"};function _(k,t,m,A,I,x){return e(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="_2-6-用ai写作-writing-with-ai" tabindex="-1">2.6 用AI写作 [Writing with AI] <a class="header-anchor" href="#_2-6-用ai写作-writing-with-ai" aria-label="Permalink to “2.6 用AI写作 [Writing with AI]”">​</a></h1><blockquote><p><strong>主题：</strong> 用 AI 写作时保留人的判断和风格，减少模板化和“机器味”。</p></blockquote><p>AI 可以帮助写作，但最好的用法不是直接让它一键生成最终稿。更有效的方式是把 AI 放进写作流程中的不同环节：找角度、列提纲、整理素材、生成初稿、改写段落、调整语气、压缩字数、检查逻辑、润色表达。</p><p><img src="'+r+'" alt="alt text"></p><p>“AI slop”可以理解为常见的 AI 腔文本：表面流畅、结构完整，但内容空泛、缺少真实细节和个人判断。它看起来像文章，却往往没有足够的信息密度。</p><p><img src="'+l+'" alt="alt text"></p><p>AI 腔常来自高频词和固定句式，例如过度使用“深入探讨”“清晰、简洁且引人入胜”“这不是……而是……”等表达。它们单独看没有问题，但反复出现会让文章显得机械。</p><p><img src="'+d+'" alt="alt text"></p><p>AI 写作不仅会影响文本本身，也会反过来影响人类表达。有些 AI 常用词开始更多出现在演讲、播客和文章中。这提醒我们：使用 AI 写作时，不能只追求完整，还要关注真实观点和个人风格。</p><h2 id="为什么不能只让-ai-直接写全文" tabindex="-1">为什么不能只让 AI 直接写全文 <a class="header-anchor" href="#为什么不能只让-ai-直接写全文" aria-label="Permalink to “为什么不能只让 AI 直接写全文”">​</a></h2><p>如果不给上下文，AI 写出来的内容容易空泛、模板化、过度正式，甚至出现明显“AI 味”。常见表现包括：</p><ul><li>大量使用抽象词；</li><li>喜欢写宽泛总结；</li><li>表达完整但缺少具体事实；</li><li>段落结构机械，像模板填空；</li><li>观点安全、平均、缺少鲜明判断。</li></ul><h2 id="更好的写作流程-先结构-后正文" tabindex="-1">更好的写作流程：先结构，后正文 <a class="header-anchor" href="#更好的写作流程-先结构-后正文" aria-label="Permalink to “更好的写作流程：先结构，后正文”">​</a></h2><p><img src="'+h+'" alt="alt text"></p><p>AI 写作更适合用在结构、素材和论证上。可以先让 AI 帮助整理资料、提出角度和生成多个大纲，而不是直接写最终稿。</p><p><img src="'+p+'" alt="alt text"></p><p>用户可以先把团队故事、写作目标和读者对象提供给 AI，然后要求它生成 3 种大纲方案。这样用户可以先判断文章逻辑，而不是在完整正文里费力改结构。</p><p><img src="'+n+'" alt="alt text"></p><p>选择大纲后，可以继续调整顺序、补充故事、移动论点、加入案例。这个阶段改动成本低，适合处理结构问题。</p><p><img src="'+o+'" alt="alt text"></p><p>大纲确定后，再让 AI 把每个小标题扩展成要点。这样可以避免一开始生成大段正文后再大面积返工。</p><p><img src="'+c+'" alt="alt text"></p><p>只有当结构、素材和重点明确后，才适合让 AI 生成正文。此时 AI 更像执行者，而不是替用户决定文章怎么写。</p><p><img src="'+b+'" alt="alt text"></p><p>大纲优先可以显著降低修改成本。结构层面的问题越早发现，越容易调整；如果直接生成终稿，后面再改往往会变成大面积重写。</p><h2 id="用-ai-写作时应提供的信息" tabindex="-1">用 AI 写作时应提供的信息 <a class="header-anchor" href="#用-ai-写作时应提供的信息" aria-label="Permalink to “用 AI 写作时应提供的信息”">​</a></h2><table tabindex="0"><thead><tr><th>信息</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td>写作目的</td><td>决定文章重点</td><td>用于公众号科普、比赛答辩、论文摘要</td></tr><tr><td>目标读者</td><td>决定解释深度</td><td>面向初学者、老师、投资人、同学</td></tr><tr><td>语气风格</td><td>控制表达方式</td><td>专业、轻松、幽默、学术、简洁</td></tr><tr><td>材料来源</td><td>避免空泛</td><td>给出真实经历、数据、案例、观点</td></tr><tr><td>禁用表达</td><td>减少 AI 味</td><td>不要写“随着时代发展”“总的来说”</td></tr><tr><td>输出格式</td><td>方便直接使用</td><td>标题、分段、小标题、要点、表格</td></tr></tbody></table><h2 id="可直接套用的-prompt-模板" tabindex="-1">可直接套用的 Prompt 模板 <a class="header-anchor" href="#可直接套用的-prompt-模板" aria-label="Permalink to “可直接套用的 Prompt 模板”">​</a></h2><h3 id="模板-1-生成多个大纲" tabindex="-1">模板 1：生成多个大纲 <a class="header-anchor" href="#模板-1-生成多个大纲" aria-label="Permalink to “模板 1：生成多个大纲”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我想写一篇关于【主题】的文章，读者是【读者】，目标是【目标】。请先不要写正文，先给我 3 种不同结构的大纲，并说明每种结构适合什么表达重点。</span></span></code></pre></div><h3 id="模板-2-减少-ai-味" tabindex="-1">模板 2：减少 AI 味 <a class="header-anchor" href="#模板-2-减少-ai-味" aria-label="Permalink to “模板 2：减少 AI 味”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请改写下面这段文字，要求更自然、更像真人写作。保留原意，减少空泛套话，不要使用“随着……”“总的来说”“具有重要意义”等模板化表达。</span></span></code></pre></div><h3 id="模板-3-补充真实细节" tabindex="-1">模板 3：补充真实细节 <a class="header-anchor" href="#模板-3-补充真实细节" aria-label="Permalink to “模板 3：补充真实细节”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请根据以下素材扩写成一段正文。要求保留具体细节和个人判断，不要写成泛泛的总结。</span></span></code></pre></div><h3 id="模板-4-检查文章逻辑" tabindex="-1">模板 4：检查文章逻辑 <a class="header-anchor" href="#模板-4-检查文章逻辑" aria-label="Permalink to “模板 4：检查文章逻辑”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请检查这篇文章的结构和论证。重点指出哪里逻辑跳跃、哪里证据不足、哪里读者可能看不懂，并给出具体修改建议。</span></span></code></pre></div><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><p>AI 写作最好用于结构、素材、论证和改写，而不是一键生成终稿。先控结构，再写正文，能明显降低 AI 味。最终文章仍然需要人来判断内容是否真实、观点是否准确、表达是否符合自己的风格。</p><hr>',39)])])}const P=a(g,[["render",_]]);export{f as __pageData,P as default};
